class Solution {
    public int countWinningSequences(String s) {
        int MOD = (int) 1e9 + 7;
        int n = s.length();
        int[][] dp = new int[n + 1][3];
        dp[0][0] = dp[0][1] = dp[0][2] = 1;

        for (int i = 1; i <= n; i++) {
            char c = s.charAt(i - 1);
            for (int j = 0; j < 3; j++) {
                for (int k = 0; k < 3; k++) {
                    if (j == k) continue;
                    if (c == 'F' && j == 'E') dp[i][k] = (dp[i][k] + dp[i - 1][j]) % MOD;
                    if (c == 'W' && j == 'F') dp[i][k] = (dp[i][k] + dp[i - 1][j]) % MOD;
                    if (c == 'E' && j == 'W') dp[i][k] = (dp[i][k] + dp[i - 1][j]) % MOD;
                }
            }
        }

        int sum = 0;
        for (int i = 0; i < 3; i++) {
            sum = (sum + dp[n][i]) % MOD;
        }
        return (int) ((long) Math.pow(3, n) - sum) % MOD;
    }
}
